import { describe, it, expect } from "vitest";
import { quote, claim } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // ---------------------------------------------------------------
  // Quote: empty and single-item base premiums (R1, R2, R8, R20)
  // ---------------------------------------------------------------

  describe("quote -- base premiums", () => {
    it.todo(
      "should return 5 G for an empty item list (processing fee only)"
    );

    it.todo(
      "should return 115 G for a single sword (100 base + 10 first-insurance + 5 fee)"
    );

    it.todo(
      "should return 71 G for a single amulet (60 base + 6 first-insurance + 5 fee)"
    );

    it.todo(
      "should return 93 G for a single staff (80 base + 8 first-insurance + 5 fee)"
    );

    it.todo(
      "should return 49 G for a single potion (40 base + 4 first-insurance + 5 fee)"
    );

    it.todo(
      "should return 33 G for a single rune component (25 base + 2.5 first-ins -> ceil(27.5) + 5 fee = 33)"
    );
  });

  // ---------------------------------------------------------------
  // Quote: component blocks (R2, E1, E2, Q1)
  // ---------------------------------------------------------------

  describe("quote -- component blocks", () => {
    it.todo(
      "should return 50 G base premium for 2 runes (2 * 25, no block)"
    );

    it.todo(
      "should return 60 G base premium for 3 runes (block of 3 alike applies)"
    );

    it.todo(
      "should return 100 G base premium for 4 runes (no block, 4 * 25)"
    );

    it.todo(
      "should return 175 G base premium for 7 runes (no block, 7 * 25)"
    );

    it.todo(
      "should return 75 G base premium for 2 runes + 1 moonstone (no block, different types)"
    );

    it.todo(
      "should return 120 G base premium for 3 runes + 3 moonstones (two separate blocks)"
    );
  });

  // ---------------------------------------------------------------
  // Quote: item-specific modifiers (R3, R4)
  // ---------------------------------------------------------------

  describe("quote -- cursed surcharge", () => {
    it.todo(
      "should add 50% surcharge to a cursed sword's base premium (100 + 50 = 150 item premium)"
    );

    it.todo(
      "should apply cursed surcharge only to the cursed item, not the whole policy -- cursed sword (100+50) + plain amulet (60) = 210 before policy modifiers and fee"
    );
  });

  describe("quote -- high-enchantment surcharge", () => {
    it.todo(
      "should add 30% surcharge for sword with enchantment exactly 5 (100 + 30 = 130 item premium)"
    );

    it.todo(
      "should NOT add high-enchantment surcharge for sword with enchantment 4"
    );

    it.todo(
      "should apply both cursed (50%) and high-enchantment (30%) surcharges when both conditions met on same item"
    );
  });

  // ---------------------------------------------------------------
  // Quote: policy-wide modifiers (R5, R6, R7)
  // ---------------------------------------------------------------

  describe("quote -- loyalty discount", () => {
    it.todo(
      "should apply 20% loyalty discount for customer with exactly 2 years with MHPCO"
    );

    it.todo(
      "should NOT apply loyalty discount for customer with 1 year with MHPCO"
    );
  });

  describe("quote -- first-insurance surcharge", () => {
    it.todo(
      "should apply 10% first-insurance surcharge to policy base premium"
    );

    it.todo(
      "should apply first-insurance surcharge even for long-standing customer (per item, not per customer)"
    );
  });

  describe("quote -- follow-up contract discount", () => {
    it.todo(
      "should NOT apply follow-up discount on the customer's first quote"
    );

    it.todo(
      "should apply 15% follow-up discount on the customer's second quote step"
    );
  });

  // ---------------------------------------------------------------
  // Quote: processing fee (R8)
  // ---------------------------------------------------------------

  describe("quote -- processing fee", () => {
    it.todo(
      "should add 5 G processing fee at the very end of every premium calculation"
    );
  });

  // ---------------------------------------------------------------
  // Quote: rounding (R10, E10)
  // ---------------------------------------------------------------

  describe("quote -- rounding", () => {
    it.todo(
      "should round premium UP (ceil) in MHPCO's favor -- e.g. 197.5 -> 198 G"
    );
  });

  // ---------------------------------------------------------------
  // Quote: integration examples (E12, E13)
  // ---------------------------------------------------------------

  describe("quote -- integration", () => {
    it.todo(
      "newcomer with cursed sword (steel, ench 3): 100 base + 50 curse + 10 first-ins = 160 + 5 fee = 165 G"
    );

    it.todo(
      "long-standing customer second contract, cursed sword (steel, ench 7): 100 base + 50 curse + 30 high-ench - 20 loyalty + 10 first-ins - 15 follow-up = 155 + 5 fee = 160 G"
    );
  });

  // ---------------------------------------------------------------
  // Claim: standard reimbursement (R11, E6)
  // ---------------------------------------------------------------

  describe("claim -- standard reimbursement", () => {
    it.todo(
      "should return payout 400 G for regular steel sword (ench 3), damage 500 G (500 - 100 deductible)"
    );

    it.todo(
      "should return payout 100 G for rune component, damage 200 G (200 - 100 deductible, no special clause)"
    );
  });

  // ---------------------------------------------------------------
  // Claim: deductible per damage event (R11, E5)
  // ---------------------------------------------------------------

  describe("claim -- deductible per damage event", () => {
    it.todo(
      "should apply 100 G deductible per damaged item -- sword 500 + amulet 300 = (400 + 200) = 600 G payout"
    );
  });

  // ---------------------------------------------------------------
  // Claim: high-enchantment clause (R13, E7)
  // ---------------------------------------------------------------

  describe("claim -- high-enchantment clause", () => {
    it.todo(
      "should reimburse at 50% for steel sword ench 9, damage 1000 -> payout 400 G (500 - 100)"
    );
  });

  // ---------------------------------------------------------------
  // Claim: dragon-material clause (R14, E7)
  // ---------------------------------------------------------------

  describe("claim -- dragon-material clause", () => {
    it.todo(
      "should fully reimburse dragon-material sword ench 5, damage 800 -> payout 700 G (800 - 100)"
    );
  });

  // ---------------------------------------------------------------
  // Claim: high-enchantment + dragon-material interaction (R15, E4, E7)
  // ---------------------------------------------------------------

  describe("claim -- enchantment vs dragon material interaction", () => {
    it.todo(
      "should apply 50% rule when dragon-material AND ench >= 8: dragon sword ench 9, damage 1000 -> payout 400 G (500 - 100)"
    );

    it.todo(
      "should apply 50% for dragon-material sword ench exactly 8, damage 1000 -> payout 400 G"
    );
  });

  // ---------------------------------------------------------------
  // Claim: payout rounding (R10, E10)
  // ---------------------------------------------------------------

  describe("claim -- payout rounding", () => {
    it.todo(
      "should round payout DOWN (floor) in MHPCO's favor -- e.g. 350.5 -> 350 G"
    );
  });

  // ---------------------------------------------------------------
  // Claim: multiple items of the same type (R16, E8)
  // ---------------------------------------------------------------

  describe("claim -- multiple items of same type", () => {
    it.todo(
      "should compute insurance sum 2000 G and cap 4000 G for two insured swords"
    );

    it.todo(
      "should apply separate deductibles when both swords are damaged in one event"
    );

    it.todo(
      "should reject claim when damages array has more entries of a type than the policy covers"
    );
  });

  // ---------------------------------------------------------------
  // Claim: cap (R12, E9)
  // ---------------------------------------------------------------

  describe("claim -- cap", () => {
    it.todo(
      "should compute cap as 2x insurance sum -- sword + amulet = 1600 sum, 3200 cap"
    );

    it.todo(
      "should base cap on unmodified insurance value -- cursed sword still has cap 2000"
    );

    it.todo(
      "should not let component block discount affect insurance sum -- sword + 3 runes = 1750 sum"
    );

    it.todo(
      "should exhaust cap across claims -- sword (sum 1000, cap 2000): first claim 1500 -> payout 1400 remaining 600; second claim 1500 -> payout 600 remaining 0"
    );
  });

  // ---------------------------------------------------------------
  // Error handling (R17, R18, R19, E11)
  // ---------------------------------------------------------------

  describe("error handling", () => {
    it.todo(
      "should reject quote with unknown item type (e.g. broomstick)"
    );

    it.todo(
      "should reject claim referencing a damage to an item not in the policy"
    );

    it.todo(
      "should reject claim with negative damage amount"
    );
  });

  // ---------------------------------------------------------------
  // CLI integration (CLI spec)
  // ---------------------------------------------------------------

  describe("CLI", () => {
    it.todo(
      "should read JSON from stdin and write JSON results to stdout"
    );

    it.todo(
      "should exit with non-zero status code and write error to stderr for unknown item type"
    );

    it.todo(
      "should exit with non-zero status code and write error to stderr for invalid claim"
    );

    it.todo(
      "should process sequential steps where a claim references an earlier quote by step index"
    );

    it.todo(
      "should return results array with same length and order as input steps"
    );

    it.todo(
      "should return premium field for quote results and payout + remainingCap for claim results"
    );
  });
});
